+    if (directive.action === 'disable') {
+      if (!hasRuleList || rules.size > 0) {
+        scopes.push({allRules: !hasRuleList, rules, enabledRules: new Set(), active: true});
+      }
+    } else if (directive.action === 'enable') {
+      if (!hasRuleList) {
+        const scope = [...scopes].reverse().find((candidate) => candidate.active);
+        if (scope) {
+          scope.active = false;
+        }
